"use client";

import { useApp } from "@/context/AppContext";
import { formatDate } from "@/utils/format";

export default function VendorBids() {
  const { bids, listings, currentUser } = useApp();

  // Get bids placed by current vendor
  const myBids = bids.filter(b => b.vendorId === currentUser?.id);

  const downloadCert = (bidId: string) => {
    const bid = bids.find(b => b.id === bidId);
    const listing = listings.find(l => l.id === bid?.listingId);
    const content = `
RECYCLING CERTIFICATE (DRAFT)
=============================
Platform: WeConnect
Date: ${new Date().toLocaleDateString()}
Status: ${bid?.status === 'accepted' ? 'CERTIFIED' : 'PENDING'}

This document certifies that ${currentUser?.name}
has agreed to recycle ${listing?.weight}kg of ${listing?.title}.

Listing ID: ${listing?.id}
Amount: ₹${bid?.amount}
----------------------------
Generated by WeConnect
`;
    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `weconnect_cert_${bidId}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="space-y-6 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
      <div className="flex justify-between items-center">
        <h2 className="text-3xl font-headline font-extrabold tracking-tight text-[color:var(--color-on-surface)]">My Bids</h2>
      </div>

      <div className="card overflow-hidden">
        <table className="data-table">
          <thead>
            <tr>
              <th>Listing</th>
              <th>Date Placed</th>
              <th>My Bid</th>
              <th>Type</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {myBids.map((bid) => {
              const listing = listings.find(l => l.id === bid.listingId);
              return (
                <tr key={bid.id}>
                  <td>
                    <p className="font-bold">{listing?.title || 'Unknown Listing'}</p>
                    <p className="text-xs text-slate-500">{listing?.id}</p>
                  </td>
                  <td>{formatDate(bid.createdAt)}</td>
                  <td>
                    <span className="font-bold text-[color:var(--color-primary)]">
                      ₹{bid.amount.toLocaleString()}
                    </span>
                  </td>
                  <td>
                    <span className="text-[10px] uppercase font-black tracking-widest text-slate-400">
                      {bid.type}
                    </span>
                  </td>
                  <td>
                    <span className={`pill ${
                      bid.status === 'accepted' ? 'pill-success' : 
                      bid.status === 'rejected' ? 'pill-error' : 
                      'pill-neutral'
                    }`}>
                      {bid.status}
                    </span>
                  </td>
                  <td>
                    <div className="flex gap-2">
                    {bid.status === 'accepted' && (
                      <button 
                        onClick={() => downloadCert(bid.id)}
                        className="btn-outline !py-1 !px-3 text-xs"
                      >
                        <span className="material-symbols-outlined text-sm">download</span>
                        Certificate
                      </button>
                    )}
                    <button className="text-slate-400 hover:text-slate-600">
                      <span className="material-symbols-outlined">more_vert</span>
                    </button>
                    </div>
                  </td>
                </tr>
              );
            })}
            {myBids.length === 0 && (
              <tr>
                <td colSpan={6} className="text-center py-10 text-slate-400">
                  You haven't placed any bids yet.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
